-- Harvest table backup
-- Created: 2026-04-21T12:18:10.520244

DROP TABLE IF EXISTS `Harvest`;
CREATE TABLE `harvest` (
  `Harvest_ID` bigint unsigned NOT NULL AUTO_INCREMENT,
  `Cart_ID` bigint unsigned NOT NULL,
  `Field_ID` bigint unsigned NOT NULL,
  `Crop_ID` bigint unsigned NOT NULL,
  `Dpt_ID` bigint unsigned NOT NULL,
  `StorLoc_ID` bigint unsigned DEFAULT NULL,
  `Load_Num` varchar(80) DEFAULT NULL,
  `Harvest_Date` date DEFAULT NULL,
  `MC` decimal(6,2) DEFAULT NULL,
  `Test_Weight` decimal(8,2) DEFAULT NULL,
  `Gross_Weight` decimal(12,2) DEFAULT NULL,
  `Tare_Weight` decimal(12,2) DEFAULT NULL,
  `Bushels` decimal(12,2) DEFAULT NULL,
  `WetBushels` decimal(12,2) DEFAULT NULL,
  `DryBushels` decimal(12,2) DEFAULT NULL,
  `Variety` varchar(120) DEFAULT NULL,
  `Load_Cell` varchar(100) DEFAULT NULL,
  `Source_File_Name` varchar(255) DEFAULT NULL,
  `Source_File_ID` bigint unsigned DEFAULT NULL,
  `External_Load_Key` varchar(255) DEFAULT NULL,
  `JobNumber` int DEFAULT NULL,
  `Note` varchar(255) DEFAULT NULL,
  `Created_At` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `Updated_At` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `Truck_ID` varchar(100) DEFAULT NULL,
  `Destination` varchar(255) DEFAULT NULL,
  `GrainCart_ID` bigint unsigned DEFAULT NULL,
  `GrainCart_FileName` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`Harvest_ID`),
  UNIQUE KEY `uq_harvest_external_load` (`External_Load_Key`),
  KEY `idx_harvest_cart` (`Cart_ID`),
  KEY `idx_harvest_field` (`Field_ID`),
  KEY `idx_harvest_crop` (`Crop_ID`),
  KEY `idx_harvest_department` (`Dpt_ID`),
  KEY `idx_harvest_storloc` (`StorLoc_ID`),
  KEY `idx_harvest_jobnumber` (`JobNumber`),
  KEY `idx_harvest_date` (`Harvest_Date`),
  CONSTRAINT `fk_harvest_cart` FOREIGN KEY (`Cart_ID`) REFERENCES `cart` (`Cart_ID`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_harvest_crop` FOREIGN KEY (`Crop_ID`) REFERENCES `crop` (`Crop_ID`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_harvest_department` FOREIGN KEY (`Dpt_ID`) REFERENCES `department` (`Dpt_ID`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_harvest_field` FOREIGN KEY (`Field_ID`) REFERENCES `field` (`Field_ID`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_harvest_storage_location` FOREIGN KEY (`StorLoc_ID`) REFERENCES `storage_location` (`StorLoc_ID`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=13917 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

